def __str__(self):
    a = "A = " + " + ".join(
        f"{coef}*x^{i}" for i, coef in enumerate(self.polyA[: self.len_A])
    )
    b = "B = " + " + ".join(
        f"{coef}*x^{i}" for i, coef in enumerate(self.polyB[: self.len_B])
    )
    c = "A*B = " + " + ".join(
        f"{coef}*x^{i}" for i, coef in enumerate(self.product)
    )

    return f"{a}\n{b}\n{c}"

