def check_matrix(matrix: list[list[int]]) -> bool:
    # must be
    matrix = [list(row) for row in matrix]
    if matrix and isinstance(matrix, list):
        if isinstance(matrix[0], list):
            prev_len = 0
            for row in matrix:
                if prev_len == 0:
                    prev_len = len(row)
                    result = True
                else:
                    result = prev_len == len(row)
        else:
            result = True
    else:
        result = False

    return result

def bfs(graph, s, t, parent):
    # Return True if there is node that has not iterated.
    visited = [False] * len(graph)
    queue = [s]
    visited[s] = True

    while queue:
        u = queue.pop(0)
        for ind in range(len(graph[u])):
            if visited[ind] is False and graph[u][ind] > 0:
                queue.append(ind)
                visited[ind] = True
                parent[ind] = u

    return visited[t]

def initializer(self, back_units):
    rng = np.random.default_rng()
    self.weight = np.asmatrix(rng.normal(0, 0.5, (self.units, back_units)))
    self.bias = np.asmatrix(rng.normal(0, 0.5, self.units)).T
    if self.activation is None:
        self.activation = sigmoid

def cal_gradient(self):
    # activation function may be sigmoid or linear
    if self.activation == sigmoid:
        gradient_mat = np.dot(self.output, (1 - self.output).T)
        gradient_activation = np.diag(np.diag(gradient_mat))
    else:
        gradient_activation = 1
    return gradient_activation

def build(self):
    for i, layer in enumerate(self.layers[:]):
        if i < 1:
            layer.is_input_layer = True
        else:
            layer.initializer(self.layers[i - 1].units)

def summary(self):
    for i, layer in enumerate(self.layers[:]):
        print(f"------- layer {i} -------")
        print("weight.shape ", np.shape(layer.weight))
        print("bias.shape ", np.shape(layer.bias))

def pooling(self, featuremaps, size_pooling, pooling_type="average_pool"):
    # pooling process
    size_map = len(featuremaps[0])
    size_pooled = int(size_map / size_pooling)
    featuremap_pooled = []
    for i_map in range(len(featuremaps)):
        feature_map = featuremaps[i_map]
        map_pooled = []
        for i_focus in range(0, size_map, size_pooling):
            for j_focus in range(0, size_map, size_pooling):
                focus = feature_map[
                    i_focus : i_focus + size_pooling,
                    j_focus : j_focus + size_pooling,
                ]
                if pooling_type == "average_pool":
                    # average pooling
                    map_pooled.append(np.average(focus))
                elif pooling_type == "max_pooling":
                    # max pooling
                    map_pooled.append(np.max(focus))
        map_pooled = np.asmatrix(map_pooled).reshape(size_pooled, size_pooled)
        featuremap_pooled.append(map_pooled)
    return featuremap_pooled

def _read32(bytestream):
    dt = np.dtype(np.uint32).newbyteorder(">")
    return np.frombuffer(bytestream.read(4), dtype=dt)[0]

