    """
    return str(self.queue)

def __init__(self):
    self.stack = []
    self.length = 0

def __str__(self):
    printed = "<" + str(self.stack)[1:-1] + ">"
    return printed

def put(self, item: Any) -> None:
    self.stack.append(item)
    self.length = self.length + 1

def rotate(self, rotation: int) -> None:
    for _ in range(rotation):
        temp = self.stack[0]
        self.stack = self.stack[1:]
        self.put(temp)
        self.length = self.length - 1

def balanced_parentheses(parentheses: str) -> bool:
    """Use a stack to check if a string of parentheses is balanced.
    >>> balanced_parentheses("([]{})")
    True
    >>> balanced_parentheses("[()]{}{[()()]()}")
    True
    >>> balanced_parentheses("[(])")
    False
    >>> balanced_parentheses("1+2*3-4")
    True
    >>> balanced_parentheses("")
    True
    """
    stack: Stack[str] = Stack()
    bracket_pairs = {"(": ")", "[": "]", "{": "}"}
    for bracket in parentheses:
        if bracket in bracket_pairs:
            stack.push(bracket)
        elif bracket in (")", "]", "}") and (
            stack.is_empty() or bracket_pairs[stack.pop()] != bracket
        ):
            return False
    return stack.is_empty()

def __init__(self, limit: int = 10):
    self.stack: list[T] = []
    self.limit = limit

def push(self, item: int) -> None:
    self.temp_queue.append(item)
    while self.main_queue:
        self.temp_queue.append(self.main_queue.popleft())
    self.main_queue, self.temp_queue = self.temp_queue, self.main_queue

def push(self, data: T) -> None:
    """add a Node to the stack"""
    if self.head is None:
        self.head = Node(data)
    else:
        new_node = Node(data)
        self.head.prev = new_node
        new_node.next = self.head
        new_node.prev = None
        self.head = new_node

def pop(self) -> T | None:
    """pop the top element off the stack"""
    if self.head is None:
        return None
    else:
        assert self.head is not None
        temp = self.head.data
        self.head = self.head.next
        if self.head is not None:
            self.head.prev = None
        return temp

def top(self) -> T | None:
    """return the top element of the stack"""
    return self.head.data if self.head is not None else None

def print_stack(self) -> None:
    print("stack elements are:")
    temp = self.head
    while temp is not None:
        print(temp.data, end="->")
        temp = temp.next

def __init__(self, data: T):
    self.data = data
    self.next: Node[T] | None = None

def __iter__(self) -> Iterator[T]:
    node = self.top
    while node:
        yield node.data
        node = node.next

